#ifndef _FEEDER_MOTOR_H_
#define _FEEDER_MOTOR_H_

#include <stdint.h>

/***************************************************************
 * 函数名称: feeder_motor_init
 * 说    明: 初始化喂食电机 GPIO (PC6, 高电平开启)
 *           因引入电机驱动模块, PC6 由 PWM 模式改为普通 GPIO 模式
 * 参    数: 无
 * 返 回 值: 无
 ***************************************************************/
void feeder_motor_init(void);

/***************************************************************
 * 函数名称: feeder_motor_control
 * 说    明: 喂食电机启停控制 (与 pump_control 逻辑完全对齐)
 *           高电平 = 开启, 低电平 = 关闭
 * 参    数:
 *       @on: 1=开启电机, 0=关闭电机
 * 返 回 值: 无
 ***************************************************************/
void feeder_motor_control(int on);

#endif /* _FEEDER_MOTOR_H_ */
